import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const darkModeRef = useRef(darkMode);

  // Sync prop to ref for animation loop
  useEffect(() => {
    darkModeRef.current = darkMode;
  }, [darkMode]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let time = 0;
    let animationFrameId: number;

    // --- Configuration ---
    const MOUNTAIN_LAYERS = 3;

    // --- Classes ---
    class Star {
        x: number;
        y: number;
        size: number;
        baseOpacity: number;
        speed: number;

        constructor() {
            this.x = Math.random() * width;
            this.y = Math.random() * height * 0.7;
            this.size = Math.random() * 1.5 + 0.5;
            this.baseOpacity = Math.random() * 0.8 + 0.2;
            this.speed = Math.random() * 0.02 + 0.005; // Slower stars
        }

        draw(ctx: CanvasRenderingContext2D, globalAlpha: number, time: number) {
            const twinkle = Math.sin(time * this.speed) * 0.3 + 0.7;
            ctx.fillStyle = `rgba(255, 255, 255, ${this.baseOpacity * twinkle * globalAlpha})`;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    class MountainLayer {
      index: number;
      offset: number;
      speed: number;

      constructor(index: number) {
        this.index = index;
        this.offset = Math.random() * 1000;
        // Significantly slower speed for "Still Life" effect
        this.speed = 0.05 * (index + 1); 
      }

      getY(x: number) {
        const t = time * 0.01;
        const xOff = x + this.offset + (t * this.speed * 5);
        const freqScale = 0.002 + (this.index * 0.001);
        const amp = height * (0.12 + (this.index * 0.04));
        const base = height * (0.92 - (this.index * 0.08)); 
        const noise = 
          Math.sin(xOff * freqScale) * 1.0 +
          Math.sin(xOff * freqScale * 2.1) * 0.5 +
          Math.sin(xOff * freqScale * 4.3) * 0.25;
        // Use Math.abs to make them look like peaks
        return base - Math.abs(noise * amp);
      }

      draw(ctx: CanvasRenderingContext2D, darkness: number) {
        // Shanshui Logic: Pure Grayscale Ink
        // Front layers are darker (more ink), back layers are lighter (more water/mist)

        // Base value: 30 (Dark Ink) to 20 (Darker Night Ink)
        const baseValue = 30 - (10 * darkness); 

        // Opacity: Front layers (low index) are clearer, back layers fade into mist
        // Index 0 (Back): Lightest opacity
        // Index 2 (Front): Darkest opacity
        const layerOpacity = 0.15 + (this.index * 0.15); 

        const r = baseValue;
        const g = baseValue;
        const b = baseValue;

        ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${layerOpacity})`;

        ctx.beginPath();
        ctx.moveTo(0, height);
        for (let x = 0; x <= width; x += 10) { // Optimization: Step 10
            ctx.lineTo(x, this.getY(x));
        }
        ctx.lineTo(width, height);
        ctx.closePath();
        ctx.fill();

        // Add a subtle "Rim" or "Ink Outline" to the top of mountains
        ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${layerOpacity + 0.1})`;
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    }

    class InkBloom {
      x: number;
      y: number;
      radius: number;
      maxRadius: number;
      alpha: number;
      growthRate: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.radius = 0;
        this.maxRadius = Math.random() * 200 + 100; // Larger, softer blooms (mist)
        this.alpha = 0;
        this.growthRate = Math.random() * 0.1 + 0.05; // Very slow growth
      }

      update() {
        if (this.radius < this.maxRadius) {
            this.radius += this.growthRate;
            if (this.alpha < 0.03) this.alpha += 0.0002;
        } else {
            this.alpha -= 0.0001; // Fade out very slowly
        }
      }

      draw(ctx: CanvasRenderingContext2D) {
        if (this.alpha <= 0) return;
        const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.radius);
        // Mist color: Off-white/Gray
        g.addColorStop(0, `rgba(200, 200, 200, ${this.alpha})`); 
        g.addColorStop(1, `rgba(200, 200, 200, 0)`);
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
        ctx.fill();
      }

      isDead() {
        return this.alpha <= 0 && this.radius >= this.maxRadius;
      }
    }

    // --- State ---
    const mountains: MountainLayer[] = [];
    const blooms: InkBloom[] = [];
    const stars: Star[] = [];

    const init = () => {
       mountains.length = 0;
       for(let i=0; i<MOUNTAIN_LAYERS; i++) {
         mountains.push(new MountainLayer(i));
       }
       stars.length = 0;
       for(let i=0; i<100; i++) {
         stars.push(new Star());
       }
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      init();
    };

    // Darkness factor (0.0 to 1.0) for transition
    let currentDarkness = 0;

    const animate = () => {
      // Transition darkness
      const targetDarkness = darkModeRef.current ? 1 : 0;
      currentDarkness += (targetDarkness - currentDarkness) * 0.02; // Slower transition

      ctx.clearRect(0, 0, width, height);
      time++;

      // Draw Stars (only if visible)
      if (currentDarkness > 0.01) {
          ctx.save();
          stars.forEach(s => s.draw(ctx, currentDarkness, time));
          ctx.restore();
      }

      // Draw Blooms (Mist/Clouds)
      if (blooms.length < 15 && Math.random() < 0.02) {
        blooms.push(new InkBloom());
      }
      for (let i = blooms.length - 1; i >= 0; i--) {
        blooms[i].update();
        blooms[i].draw(ctx);
        if (blooms[i].isDead()) blooms.splice(i, 1);
      }

      // Draw Mountains
      mountains.forEach(m => m.draw(ctx, currentDarkness));

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-all duration-1000 ${darkMode ? 'opacity-100' : 'opacity-80'}`}
      style={{ mixBlendMode: darkMode ? 'normal' : 'multiply' }}
    />
  );
};

export default InkCanvas;

