import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const darkModeRef = useRef(darkMode);

  // Sync prop to ref for animation loop
  useEffect(() => {
    darkModeRef.current = darkMode;
  }, [darkMode]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let time = 0;
    let animationFrameId: number;

    // --- Configuration ---
    const MOUNTAIN_LAYERS = 3;

    // --- Classes ---
    class Star {
        x: number;
        y: number;
        size: number;
        baseOpacity: number;
        speed: number;

        constructor() {
            this.x = Math.random() * width;
            this.y = Math.random() * height * 0.7;
            this.size = Math.random() * 1.5 + 0.5;
            this.baseOpacity = Math.random() * 0.8 + 0.2;
            this.speed = Math.random() * 0.02 + 0.005; // Slower stars
        }

        draw(ctx: CanvasRenderingContext2D, globalAlpha: number, time: number) {
            const twinkle = Math.sin(time * this.speed) * 0.3 + 0.7;
            ctx.fillStyle = `rgba(255, 255, 255, ${this.baseOpacity * twinkle * globalAlpha})`;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    class MountainLayer {
      index: number;
      offset: number;
      speed: number;

      constructor(index: number) {
        this.index = index;
        this.offset = Math.random() * 1000;
        // Significantly slower speed for "Still Life" effect
        this.speed = 0.02 * (index + 1); 
      }

      getY(x: number) {
        const t = time * 0.01;
        const xOff = (x * 0.002) + this.offset + (t * this.speed);

        // Simulating hand-drawn ink strokes - smoother, rolling hills
        const amp = height * (0.15 + (this.index * 0.05));
        const base = height * (0.85 - (this.index * 0.12)); 

        const noise = 
          Math.sin(xOff) * 1.0 +
          Math.sin(xOff * 2.1) * 0.4 +
          Math.cos(xOff * 4.3) * 0.15;

        return base - Math.abs(noise * amp);
      }

      draw(ctx: CanvasRenderingContext2D, darkness: number) {
        // Shanshui Logic: Pure Grayscale Ink
        // Front layers are darker (more ink), back layers are lighter (more water/mist)

        // Darkness determines if we are in "Night Mode" (heavy ink) or "Day Mode" (wash)
        const isNight = darkness > 0.5;

        // Base Intensity
        // Light Mode: 180 (Light Grey) -> 80 (Dark Grey)
        // Dark Mode: 40 (Dark Grey) -> 10 (Black)
        const lightBase = 180 - (this.index * 40);
        const darkBase = 40 - (this.index * 10);

        const val = lightBase + (darkBase - lightBase) * darkness;

        // Opacity
        const opacity = 0.3 + (this.index * 0.2) + (darkness * 0.2);

        const r = val;
        const g = val;
        const b = val;

        // Ink Wash Gradient: Solid at top edge, fading to mist at bottom
        const gradient = ctx.createLinearGradient(0, height * 0.4, 0, height);
        gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${opacity})`);
        gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, ${opacity * 0.2})`); // Fade out

        ctx.fillStyle = gradient;

        ctx.beginPath();
        ctx.moveTo(0, height);
        for (let x = 0; x <= width; x += 10) { 
            ctx.lineTo(x, this.getY(x));
        }
        ctx.lineTo(width, height);
        ctx.closePath();
        ctx.fill();

        // Ink Outline (Rim)
        ctx.strokeStyle = `rgba(${r-20}, ${g-20}, ${b-20}, ${opacity + 0.1})`;
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    }

    class InkBloom {
      x: number;
      y: number;
      radius: number;
      maxRadius: number;
      alpha: number;
      growthRate: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.radius = 0;
        this.maxRadius = Math.random() * 200 + 100; // Larger, softer blooms (mist)
        this.alpha = 0;
        this.growthRate = Math.random() * 0.1 + 0.05; // Very slow growth
      }

      update() {
        if (this.radius < this.maxRadius) {
            this.radius += this.growthRate;
            if (this.alpha < 0.05) this.alpha += 0.0002;
        } else {
            this.alpha -= 0.0001; // Fade out very slowly
        }
      }

      draw(ctx: CanvasRenderingContext2D, darkness: number) {
        if (this.alpha <= 0) return;
        const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.radius);

        // Mist color: 
        // Light Mode: White/Paper color
        // Dark Mode: Dark Grey
        const c = 255 - (darkness * 200);

        g.addColorStop(0, `rgba(${c}, ${c}, ${c}, ${this.alpha})`); 
        g.addColorStop(1, `rgba(${c}, ${c}, ${c}, 0)`);
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
        ctx.fill();
      }

      isDead() {
        return this.alpha <= 0 && this.radius >= this.maxRadius;
      }
    }

    // --- State ---
    const mountains: MountainLayer[] = [];
    const blooms: InkBloom[] = [];
    const stars: Star[] = [];

    const init = () => {
       mountains.length = 0;
       for(let i=0; i<MOUNTAIN_LAYERS; i++) {
         mountains.push(new MountainLayer(i));
       }
       stars.length = 0;
       for(let i=0; i<100; i++) {
         stars.push(new Star());
       }
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      init();
    };

    // Darkness factor (0.0 to 1.0) for transition
    let currentDarkness = 0;

    const animate = () => {
      // Transition darkness
      const targetDarkness = darkModeRef.current ? 1 : 0;
      currentDarkness += (targetDarkness - currentDarkness) * 0.02; // Slower transition

      ctx.clearRect(0, 0, width, height);
      time++;

      // Draw Stars (only if visible)
      if (currentDarkness > 0.1) {
          ctx.save();
          stars.forEach(s => s.draw(ctx, currentDarkness, time));
          ctx.restore();
      }

      // Draw Blooms (Mist/Clouds)
      if (blooms.length < 15 && Math.random() < 0.01) {
        blooms.push(new InkBloom());
      }
      for (let i = blooms.length - 1; i >= 0; i--) {
        blooms[i].update();
        blooms[i].draw(ctx, currentDarkness);
        if (blooms[i].isDead()) blooms.splice(i, 1);
      }

      // Draw Mountains
      mountains.forEach(m => m.draw(ctx, currentDarkness));

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-all duration-1000 ${darkMode ? 'opacity-100' : 'opacity-60'}`}
      style={{ mixBlendMode: 'multiply' }}
    />
  );
};

